={
  "systemInstruction": {
    "parts": [{ "text": "You are a payroll input parser. Given an unstructured HR message (email, Slack, WhatsApp), extract structured fields according to the strict schema. Return confidence_scores as decimals between 0 and 1 for each extracted field. Add ambiguity_flags for anything unclear (missing employee name, missing currency, unclear intent, etc.). Do not hallucinate values — use null if unsure. Do not wrap in markdown. Output ONLY the JSON object." }]
  },
  "contents": [{
    "role": "user",
    "parts": [{ "text": {{ JSON.stringify($json[0].raw_text) }} }]
  }],
  "generationConfig": {
    "temperature": 0.1,
    "maxOutputTokens": 800,
    "thinkingConfig": { "thinkingBudget": 0 },
    "responseMimeType": "application/json",
    "responseSchema": {
      "type": "OBJECT",
      "properties": {
        "employee_name_guess": { "type": "STRING", "nullable": true },
        "country_hint": { "type": "STRING", "nullable": true },
        "change_type": {
          "type": "STRING",
          "enum": ["bonus","address","salary","leave","tax_code","bank_change","other"]
        },
        "amount": { "type": "NUMBER", "nullable": true },
        "currency": { "type": "STRING", "nullable": true },
        "effective_date": { "type": "STRING", "nullable": true },
        "confidence_scores": {
          "type": "OBJECT",
          "properties": {
            "employee": { "type": "NUMBER" },
            "change_type": { "type": "NUMBER" },
            "amount": { "type": "NUMBER" },
            "effective_date": { "type": "NUMBER" }
          }
        },
        "ambiguity_flags": {
          "type": "ARRAY",
          "items": { "type": "STRING" }
        }
      },
      "required": ["change_type","confidence_scores","ambiguity_flags"]
    }
  }
}

parameters.jsCode:
// Gemini 2.5 Flash returns JSON guaranteed by responseSchema.
const resp = $input.first().json;
const messageRow = $('Fetch message').first().json;
const messageId = messageRow.id;

const rawText = resp.candidates?.[0]?.content?.parts?.[0]?.text ?? '';
if (!rawText) {
  throw new Error('Empty Gemini response: ' + JSON.stringify(resp).slice(0, 300));
}
const parsed = JSON.parse(rawText);

// Overall confidence = min of per-field confidences, or 0.5 if none.
const scores = Object.values(parsed.confidence_scores ?? {});
const overall = scores.length
  ? Math.min(...scores.map((n) => Number(n) || 0))
  : 0.5;

return [{
  json: {
    message_id: messageId,
    parsed_fields: parsed,
    ambiguity_flags: parsed.ambiguity_flags ?? [],
    confidence_overall: Number(overall.toFixed(2)),
    organization_id: messageRow.organization_id,
  },
}];
